const App = () => {
  const part1 = 'Fundamentals of React'
  const exercises1 = 10
  const part2 = 'Using props tco pass data'
  const exercises2 = 7
  const part3 = 'State of a component'
  const exercises3 = 14
  const fsocourse = {
    name: 'Half Stack application development',
    parts: [
      {
        name: 'Fundamentals of React',
        exercises: 10
      },
      {
        name: 'Using props tco pass data',
        exercises: 7
      },
      {
        name: 'State of a component',
        exercises: 14
      }
    ]

  }
  return (
    <div>
      <Header fsocourse={fsocourse.name} />
    </div>
  )
}
const Header = (props) => {
  return (
    <h1>{props.fsocourse}</h1>
  )
}

const Content = () => {
  return (
    <div>
      <p>
        { }
      </p>
      <p>
        {part2} {exercises2}
      </p>
      <p>
        {part3} {exercises3}
      </p>
    </div>
  )
}
const Total = (props) => {
  const exercises1 = 10
  const exercises2 = 7
  const exercises3 = 14


  return (
    <div>
      <p>Number of exercises {exercises1 + exercises2 + exercises3}</p>
    </div>
  )
}

export default App
